        &self,
        coordinates: &[PhiloxCoordinate],
    ) -> Result<Vec<[u32; 4]>, CudaError> {
        if coordinates.is_empty() {
            return Ok(Vec::new());
        }
        let count = u32::try_from(coordinates.len()).map_err(|_| {
            CudaError::InvalidInput("Philox vector count exceeds u32 capacity".to_owned())
